sql:
SELECT AVG(access_count) as average_access_per_user
FROM (
    SELECT COUNT(al.access_id) as access_count
    FROM access_logs al
    GROUP BY al.user_id
) as user_access_counts;

SELECT AVG(marker_id) AS average_marker_id
FROM cell_type_markers
WHERE cell_type_id = 200;

external_knowledge:
- 'Stars' in the question metaphorically represent cell types with labels starting with "Astro";
- 'Shine brightly' corresponds to markers with high expression levels;
- 'Observed more than 100 times' refers to access counts greater than 100;
- 'Astronomers' symbolize the users accessing these cell types;
- 'Cosmic year 2022' is a metaphor for the specified date range;
- 'Constellations' refer to the cell type categories;
- 'Instruments used for the observation' refer to the specific markers used;
- 'Observatories' metaphorically represent the research teams.

sql:
SELECT AVG(number_of_users) AS average_users_per_team
FROM (
  SELECT COUNT(user_id) AS number_of_users
  FROM team_members
  GROUP BY team_id
) AS user_counts_per_team;

SELECT COUNT(DISTINCT cell_type_markers.cell_type_id) AS total_cell_types
FROM cell_type_markers
WHERE cell_type_markers.marker_expression_level = 'high';

SELECT cell_type_id, label, expanded_label, obo_ontology_id, category, description
FROM cell_types
ORDER BY cell_type_id;

SELECT cell_types.label, cell_type_functions.function 
FROM cell_types 
INNER JOIN cell_type_functions ON cell_types.cell_type_id = cell_type_functions.cell_type_id;
